# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.spec_compiler.parse_guarantee","kind":"function","src_hash":"d4ffa49382b9ab76","in":{"base":"str"},"out":{"base":"CompiledSpec"},"spec":{"lhs":"parse_guarantee(tex)","rhs":"parse a @guarantee text into a compiledspec","over":{"base":"str"},"name":"parse_guarantee_correct"},"guarantee":"parse a @guarantee text into a compiledspec","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.spec_compiler.parse_guarantee_correct","statement":"Path(parse_guarantee(x), parse a @guarantee text into a compiledspec)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d5d565798f9931c0"}
def parse_guarantee(text: str) -> CompiledSpec:
    """Parse a @guarantee text into a CompiledSpec.

    Analyzes the natural language specification and decomposes it
    into structural (Z3-decidable) and semantic (oracle) predicates.

    Parameters
    ----------
    text : str
        The guarantee text, e.g., "returns a sorted list with no duplicates".

    Returns
    -------
    CompiledSpec
        The compiled specification.
    """
    text_lower = text.lower().strip()
    spec = CompiledSpec(original_text=text)

    # Detect return type hints
    spec.return_type = _infer_return_type(text_lower)

    # Match structural predicates
    for keywords, name, formula, fragment in _STRUCTURAL_PATTERNS:
        if any(kw in text_lower for kw in keywords):
            spec.structural.append(StructuralPredicate(
                name=name,
                formula=formula,
                z3_fragment=fragment,
            ))

    # Match semantic predicates
    for keywords, name in _SEMANTIC_PATTERNS:
        if any(kw in text_lower for kw in keywords):
            spec.semantic.append(SemanticPredicate(
                name=name,
                description=text,
            ))

    # If no patterns matched, treat the whole thing as semantic
    if not spec.structural and not spec.semantic:
        spec.semantic.append(SemanticPredicate(
            name='full_spec',
            description=text,
        ))

    return spec


