# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.spec_compiler._infer_return_type","kind":"function","src_hash":"b05fe3edf1f89fe3","in":{"base":"str"},"out":{"base":"str"},"spec":{"lhs":"_infer_return_type(tex)","rhs":"infer the return type from natural language","over":{"base":"str"},"name":"_infer_return_type_correct"},"guarantee":"infer the return type from natural language","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.spec_compiler._infer_return_type_correct","statement":"Path(_infer_return_type(x), infer the return type from natural language)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ff432da7f1be0bcb"}
def _infer_return_type(text: str) -> str:
    """Infer the return type from natural language."""
    if any(w in text for w in ['list', 'array', 'sequence', 'elements']):
        return 'List'
    if any(w in text for w in ['dict', 'dictionary', 'mapping']):
        return 'Dict'
    if any(w in text for w in ['set', 'unique set']):
        return 'Set'
    if any(w in text for w in ['number', 'integer', 'int', 'count']):
        return 'int'
    if any(w in text for w in ['string', 'str', 'text']):
        return 'str'
    if any(w in text for w in ['bool', 'boolean', 'true', 'false']):
        return 'bool'
    if any(w in text for w in ['float', 'decimal', 'real']):
        return 'float'
    return 'Any'


