# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.spec_compiler.verify_against_spec","kind":"function","src_hash":"224ef4cc54c542a9","in":{"base":"OTerm"},"out":{"base":"Tuple[CompiledSpec, VerificationResult]"},"spec":{"lhs":"verify_against_spec(cod)","rhs":"verify that a code oterm satisfies a guarantee","over":{"base":"OTerm"},"name":"verify_against_spec_correct"},"guarantee":"verify that a code oterm satisfies a guarantee","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.spec_compiler.verify_against_spec_correct","statement":"Path(verify_against_spec(x), verify that a code oterm satisfies a guarantee)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"b86dde7d8827dde6"}
def verify_against_spec(
    code_oterm: OTerm,
    guarantee_text: str,
    proof: Optional[ProofTerm] = None,
    ctx: Optional[ProofContext] = None,
) -> Tuple[CompiledSpec, VerificationResult]:
    """Verify that a code OTerm satisfies a guarantee.

    Parameters
    ----------
    code_oterm : OTerm
        The denotational semantics of the code.
    guarantee_text : str
        The @guarantee text.
    proof : ProofTerm, optional
        An explicit proof. If None, a skeleton is generated.
    ctx : ProofContext, optional
        Proof context.

    Returns
    -------
    (CompiledSpec, VerificationResult)
    """
    spec = compile_guarantee_to_type(guarantee_text)
    spec_oterm = spec.to_oterm()

    if proof is None:
        proof = spec.generate_proof_skeleton()

    result = check_proof(proof, code_oterm, spec_oterm, ctx)
    return spec, result


