# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.spec_compiler.spec_to_markdown","kind":"function","src_hash":"5cd551869b410bde","in":{"base":"CompiledSpec"},"out":{"base":"str"},"spec":{"lhs":"spec_to_markdown(spe)","rhs":"render a compiled spec as markdown documentation","over":{"base":"CompiledSpec"},"name":"spec_to_markdown_correct"},"guarantee":"render a compiled spec as markdown documentation","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.spec_compiler.spec_to_markdown_correct","statement":"Path(spec_to_markdown(x), render a compiled spec as markdown documentation)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"38cd9cfe209c331a"}
def spec_to_markdown(spec: CompiledSpec) -> str:
    """Render a compiled spec as Markdown documentation."""
    lines = [
        f'## Specification: {spec.original_text}',
        '',
        f'**Σ-type**: `{spec.sigma_type_str()}`',
        '',
        f'**Return type**: `{spec.return_type}`',
        '',
    ]

    if spec.structural:
        lines.append('### Structural Predicates (Z3-decidable)')
        for sp in spec.structural:
            lines.append(f'- **{sp.name}**: `{sp.formula}` [{sp.z3_fragment}]')
        lines.append('')

    if spec.semantic:
        lines.append('### Semantic Predicates (oracle-judged)')
        for sem in spec.semantic:
            lines.append(f'- **{sem.name}**: {sem.description} '
                         f'(threshold: {sem.confidence_threshold})')
        lines.append('')

    obligations = spec.proof_obligations()
    if obligations:
        lines.append('### Proof Obligations')
        for i, obl in enumerate(obligations, 1):
            lines.append(f'{i}. [{obl["kind"]}] **{obl["name"]}**: {obl.get("formula", obl.get("description", ""))}')
        lines.append('')

    return '\n'.join(lines)
